def solve(nums, target):
    left, right = 0, len(nums) - 1
    while left < right:
        total = nums[left] + nums[right]
        if total == target:
            return left, right
        if total < target:
            left += 1
        else:
            right -= 1
    return -1, -1

# Pitfall-specific checks
def check_no_solution(nums, target):
    return all(num < target for num in nums) or all(num > target for num in nums)

# Example usage of the check
def solve_with_check(nums, target):
    if check_no_solution(nums, target):
        return -1, -1
    return solve(nums, target)
